function m(t){const[e,n]=t.split(" "),[r,a,o]=e.split("-").map(Number),[s,u,i]=n?n.split(":").map(Number):[0,0,0];return new Date(r,a-1,o,s,u,i)}function c(t){return t.getDate().toString()}function p(t){const n=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"][t.getMonth()],r=t.getFullYear();return`${n} ${r}`}function f(t,e){return t.getTime()<e.getTime()}export{p as a,c as f,f as i,m as p};
